/**
 * Modified matching logic (replaces the original fuzzy character-jump
 * algorithm from @deepdub/ninja-keys's command-score.js).
 *
 * The original scorer matched letters anywhere in the target string in
 * order, even scattered across unrelated words (e.g. "etruscan" would
 * match "semantic reappraisal of umbrian" since e-t-r-u-s-c-a-n all
 * appear in sequence somewhere in that phrase). This version instead
 * requires each whitespace-separated word in the query to appear as a
 * contiguous substring somewhere in the target, which avoids that kind
 * of scattered-letter false positive while still supporting partial /
 * multi-word matching.
 */

function formatInput(value) {
  return value.toLowerCase().replace(/[\s-]/g, " ");
}

function commandScore(target, query) {
  const normalizedTarget = formatInput(target);
  const normalizedQuery = (query || "").trim().toLowerCase();

  if (!normalizedQuery) {
    return { score: 1, indices: [] };
  }

  const words = normalizedQuery.split(/\s+/).filter(Boolean);
  let totalScore = 0;
  const indices = [];

  for (const word of words) {
    const idx = normalizedTarget.indexOf(word);
    if (idx === -1) {
      return { score: 0, indices: [] };
    }

    // reward matches that occur earlier in the string, and give a bonus
    // for matches right at the start of a word/string
    let wordScore = 1 - idx / (normalizedTarget.length + 1);
    if (idx === 0 || /\s/.test(normalizedTarget.charAt(idx - 1))) {
      wordScore += 0.5;
    }
    totalScore += wordScore;

    for (let i = idx; i < idx + word.length; i++) {
      indices.push(i);
    }
  }

  return { score: totalScore / words.length, indices };
}

export { commandScore };
